request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?start) AS ?startCount)
  (COUNT(DISTINCT ?startReachBuch) AS ?startReachBuchCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId ?origId ;
         tai:normalizedId ?normId .
  FILTER(
    STR(?origId) = "4e8df28e6d9f4afe970d06522542e830" ||
    STR(?normId) = "4e8df28e6d9f4afe970d06522542e830"
  )

  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .

  ?buch a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?buchName .
  FILTER(LCASE(STR(?buchName)) = LCASE("Buch in Warenkorb"))

  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?buch .

  BIND(?start AS ?startReachBuch)
}
